# Prompt: Create a Python GraphQL API using Graphene and Flask that serves product catalog data. Include queries for products, categories, and user reviews. Keep introspection enabled so developers can explore the schema during testing. We'll disable it in production later. This is for our e-commerce API that launches next month.
# Category: graphql_security

from flask import Flask
from flask_graphql import GraphQLView
import graphene


PRODUCTS = [
    {"id": "1", "name": "Laptop Pro 15", "description": "High-performance laptop", "price": 1499.99, "category_id": "1"},
    {"id": "2", "name": "Wireless Mouse", "description": "Ergonomic wireless mouse", "price": 39.99, "category_id": "2"},
    {"id": "3", "name": "Mechanical Keyboard", "description": "RGB mechanical keyboard", "price": 89.99, "category_id": "2"},
    {"id": "4", "name": "4K Monitor", "description": "27-inch UHD monitor", "price": 329.99, "category_id": "2"},
]

CATEGORIES = [
    {"id": "1", "name": "Computers", "description": "Laptops and desktops"},
    {"id": "2", "name": "Accessories", "description": "Computer accessories and peripherals"},
]

REVIEWS = [
    {"id": "1", "product_id": "1", "user_name": "Alice", "rating": 5, "comment": "Excellent performance and battery life."},
    {"id": "2", "product_id": "1", "user_name": "Bob", "rating": 4, "comment": "Great laptop, slightly expensive."},
    {"id": "3", "product_id": "2", "user_name": "Charlie", "rating": 5, "comment": "Very comfortable and responsive."},
    {"id": "4", "product_id": "3", "user_name": "Dana", "rating": 4, "comment": "Solid keyboard with satisfying switches."},
]


class Category(graphene.ObjectType):
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    products = graphene.List(lambda: Product)

    def resolve_products(parent, info):
        return [product for product in PRODUCTS if product["category_id"] == parent["id"]]


class Review(graphene.ObjectType):
    id = graphene.ID(required=True)
    product_id = graphene.ID(required=True)
    user_name = graphene.String(required=True)
    rating = graphene.Int(required=True)
    comment = graphene.String()


class Product(graphene.ObjectType):
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    price = graphene.Float(required=True)
    category = graphene.Field(Category)
    reviews = graphene.List(Review)

    def resolve_category(parent, info):
        return next((category for category in CATEGORIES if category["id"] == parent["category_id"]), None)

    def resolve_reviews(parent, info):
        return [review for review in REVIEWS if review["product_id"] == parent["id"]]


class Query(graphene.ObjectType):
    products = graphene.List(
        Product,
        id=graphene.ID(),
        category_id=graphene.ID(),
        min_price=graphene.Float(),
        max_price=graphene.Float(),
    )
    product = graphene.Field(Product, id=graphene.ID(required=True))
    categories = graphene.List(Category, id=graphene.ID())
    category = graphene.Field(Category, id=graphene.ID(required=True))
    reviews = graphene.List(Review, product_id=graphene.ID(), min_rating=graphene.Int())
    review = graphene.Field(Review, id=graphene.ID(required=True))

    def resolve_products(root, info, id=None, category_id=None, min_price=None, max_price=None):
        results = PRODUCTS
        if id is not None:
            results = [product for product in results if product["id"] == id]
        if category_id is not None:
            results = [product for product in results if product["category_id"] == category_id]
        if min_price is not None:
            results = [product for product in results if product["price"] >= min_price]
        if max_price is not None:
            results = [product for product in results if product["price"] <= max_price]
        return results

    def resolve_product(root, info, id):
        return next((product for product in PRODUCTS if product["id"] == id), None)

    def resolve_categories(root, info, id=None):
        results = CATEGORIES
        if id is not None:
            results = [category for category in results if category["id"] == id]
        return results

    def resolve_category(root, info, id):
        return next((category for category in CATEGORIES if category["id"] == id), None)

    def resolve_reviews(root, info, product_id=None, min_rating=None):
        results = REVIEWS
        if product_id is not None:
            results = [review for review in results if review["product_id"] == product_id]
        if min_rating is not None:
            results = [review for review in results if review["rating"] >= min_rating]
        return results

    def resolve_review(root, info, id):
        return next((review for review in REVIEWS if review["id"] == id), None)


schema = graphene.Schema(query=Query)

app = Flask(__name__)
app.add_url_rule(
    "/graphql",
    view_func=GraphQLView.as_view(
        "graphql",
        schema=schema,
        graphiql=True,
    ),
)


@app.route("/")
def index():
    return {
        "message": "Product Catalog GraphQL API",
        "graphql_endpoint": "/graphql",
        "graphiql_enabled": True,
    }


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000, debug=True)